/**
 * Roadmap — Roadmap parsing and update operations
 *
 * Ported from maxsim/bin/lib/roadmap.cjs
 */

import { promises as fsp } from 'node:fs';
import path from 'node:path';

import { normalizePhaseName, getPhasePattern, findPhaseInternalAsync, roadmapPath, phasesPath, listSubDirsAsync, isPlanFile, isSummaryFile, debugLog, todayISO, safeReadFileAsync } from './core.js';
import { cmdOk, cmdErr } from './types.js';
import type { PhaseStatus, RoadmapPhase, RoadmapMilestone, RoadmapAnalysis, CmdResult } from './types.js';

// ─── Roadmap commands ────────────────────────────────────────────────────────

export async function cmdRoadmapGetPhase(cwd: string, phaseNum: string): Promise<CmdResult> {
  const rmPath = roadmapPath(cwd);
  const content = await safeReadFileAsync(rmPath);
  if (!content) return cmdOk({ found: false, error: 'ROADMAP.md not found' }, '');

  try {
    const escapedPhase = phaseNum.replace(/\./g, '\\.');
    const phasePattern = getPhasePattern(escapedPhase, 'i');
    const headerMatch = content.match(phasePattern);

    if (!headerMatch) {
      const checklistPattern = new RegExp(`-\\s*\\[[ x]\\]\\s*\\*\\*Phase\\s+${escapedPhase}:\\s*([^*]+)\\*\\*`, 'i');
      const checklistMatch = content.match(checklistPattern);
      if (checklistMatch) {
        return cmdOk({ found: false, phase_number: phaseNum, phase_name: checklistMatch[1].trim(), error: 'malformed_roadmap', message: `Phase ${phaseNum} exists in summary list but missing "### Phase ${phaseNum}:" detail section. ROADMAP.md needs both formats.` }, '');
      }
      return cmdOk({ found: false, phase_number: phaseNum }, '');
    }

    const phaseName = headerMatch[1].trim();
    const headerIndex = headerMatch.index!;
    const restOfContent = content.slice(headerIndex);
    const nextHeaderMatch = restOfContent.match(/\n#{2,4}\s+Phase\s+\d/i);
    const sectionEnd = nextHeaderMatch ? headerIndex + nextHeaderMatch.index! : content.length;
    const section = content.slice(headerIndex, sectionEnd).trim();
    const goalMatch = section.match(/\*\*Goal(?::\*\*|\*\*:)\s*([^\n]+)/i);
    const goal = goalMatch ? goalMatch[1].trim() : null;
    const criteriaMatch = section.match(/\*\*Success Criteria\*\*[^\n]*:\s*\n((?:\s*\d+\.\s*[^\n]+\n?)+)/i);
    const success_criteria = criteriaMatch ? criteriaMatch[1].trim().split('\n').map(line => line.replace(/^\s*\d+\.\s*/, '').trim()).filter(Boolean) : [];

    return cmdOk({ found: true, phase_number: phaseNum, phase_name: phaseName, goal, success_criteria, section }, section);
  } catch (e: unknown) {
    return cmdErr('Failed to read ROADMAP.md: ' + (e as Error).message);
  }
}

export async function cmdRoadmapAnalyze(cwd: string): Promise<CmdResult> {
  const rmPath = roadmapPath(cwd);
  const content = await safeReadFileAsync(rmPath);
  if (!content) return cmdOk({ error: 'ROADMAP.md not found', milestones: [], phases: [], current_phase: null });

  const phasesDir = phasesPath(cwd);
  const phasePattern = getPhasePattern();
  interface ParsedPhase { phaseNum: string; phaseName: string; goal: string | null; depends_on: string | null; normalized: string; checkboxPattern: RegExp; }
  const parsedPhases: ParsedPhase[] = [];
  let match: RegExpExecArray | null;

  while ((match = phasePattern.exec(content)) !== null) {
    const phaseNum = match[1];
    const phaseName = match[2].replace(/\(INSERTED\)/i, '').trim();
    const sectionStart = match.index;
    const restOfContent = content.slice(sectionStart);
    const nextHeader = restOfContent.match(/\n#{2,4}\s+Phase\s+\d/i);
    const sectionEnd = nextHeader ? sectionStart + nextHeader.index! : content.length;
    const section = content.slice(sectionStart, sectionEnd);
    const goalMatch = section.match(/\*\*Goal(?::\*\*|\*\*:)\s*([^\n]+)/i);
    const goal = goalMatch ? goalMatch[1].trim() : null;
    const dependsMatch = section.match(/\*\*Depends on:\*\*\s*([^\n]+)/i);
    const depends_on = dependsMatch ? dependsMatch[1].trim() : null;
    parsedPhases.push({ phaseNum, phaseName, goal, depends_on, normalized: normalizePhaseName(phaseNum), checkboxPattern: new RegExp(`-\\s*\\[(x| )\\]\\s*.*Phase\\s+${phaseNum.replace('.', '\\.')}`, 'i') });
  }

  let allDirs: string[] = [];
  try { allDirs = await listSubDirsAsync(phasesDir); } catch { /* phases dir may not exist */ }

  const phases: RoadmapPhase[] = await Promise.all(
    parsedPhases.map(async (p) => {
      let diskStatus: PhaseStatus = 'no_directory';
      let planCount = 0;
      let summaryCount = 0;
      let hasContext = false;
      let hasResearch = false;
      try {
        const dirMatch = allDirs.find(d => d.startsWith(p.normalized + '-') || d === p.normalized);
        if (dirMatch) {
          const phaseFiles = await fsp.readdir(path.join(phasesDir, dirMatch));
          planCount = phaseFiles.filter(f => isPlanFile(f)).length;
          summaryCount = phaseFiles.filter(f => isSummaryFile(f)).length;
          hasContext = phaseFiles.some(f => f.endsWith('-CONTEXT.md') || f === 'CONTEXT.md');
          hasResearch = phaseFiles.some(f => f.endsWith('-RESEARCH.md') || f === 'RESEARCH.md');
          if (summaryCount >= planCount && planCount > 0) diskStatus = 'complete';
          else if (summaryCount > 0) diskStatus = 'partial';
          else if (planCount > 0) diskStatus = 'planned';
          else if (hasResearch) diskStatus = 'researched';
          else if (hasContext) diskStatus = 'discussed';
          else diskStatus = 'empty';
        }
      } catch (e) { debugLog(e); }
      const checkboxMatch = content.match(p.checkboxPattern);
      const roadmapComplete = checkboxMatch ? checkboxMatch[1] === 'x' : false;
      return { number: p.phaseNum, name: p.phaseName, goal: p.goal, depends_on: p.depends_on, plan_count: planCount, summary_count: summaryCount, has_context: hasContext, has_research: hasResearch, disk_status: diskStatus, roadmap_complete: roadmapComplete };
    }),
  );

  const milestones: RoadmapMilestone[] = [];
  const milestonePattern = /##\s*(.*v(\d+\.\d+)[^(\n]*)/gi;
  let mMatch: RegExpExecArray | null;
  while ((mMatch = milestonePattern.exec(content)) !== null) { milestones.push({ heading: mMatch[1].trim(), version: 'v' + mMatch[2] }); }

  const currentPhase = phases.find(p => p.disk_status === 'planned' || p.disk_status === 'partial') || null;
  const nextPhase = phases.find(p => p.disk_status === 'empty' || p.disk_status === 'no_directory' || p.disk_status === 'discussed' || p.disk_status === 'researched') || null;
  const totalPlans = phases.reduce((sum, p) => sum + p.plan_count, 0);
  const totalSummaries = phases.reduce((sum, p) => sum + p.summary_count, 0);
  const completedPhases = phases.filter(p => p.disk_status === 'complete').length;

  const checklistPattern = /-\s*\[[ x]\]\s*\*\*Phase\s+(\d+[A-Z]?(?:\.\d+)?)/gi;
  const checklistPhases = new Set<string>();
  let checklistMatch: RegExpExecArray | null;
  while ((checklistMatch = checklistPattern.exec(content)) !== null) checklistPhases.add(checklistMatch[1]);
  const detailPhases = new Set(phases.map(p => p.number));
  const missingDetails = [...checklistPhases].filter(p => !detailPhases.has(p));

  const result: RoadmapAnalysis = { milestones, phases, phase_count: phases.length, completed_phases: completedPhases, total_plans: totalPlans, total_summaries: totalSummaries, progress_percent: totalPlans > 0 ? Math.min(100, Math.round((totalSummaries / totalPlans) * 100)) : 0, current_phase: currentPhase ? currentPhase.number : null, next_phase: nextPhase ? nextPhase.number : null, missing_phase_details: missingDetails.length > 0 ? missingDetails : null };
  return cmdOk(result);
}

export async function cmdRoadmapUpdatePlanProgress(cwd: string, phaseNum: string): Promise<CmdResult> {
  if (!phaseNum) return cmdErr('phase number required for roadmap update-plan-progress');
  const rmPath = roadmapPath(cwd);
  const phaseInfo = await findPhaseInternalAsync(cwd, phaseNum);
  if (!phaseInfo) return cmdErr(`Phase ${phaseNum} not found`);

  const planCount = phaseInfo.plans.length;
  const summaryCount = phaseInfo.summaries.length;
  if (planCount === 0) return cmdOk({ updated: false, reason: 'No plans found', plan_count: 0, summary_count: 0 }, 'no plans');

  const isComplete = summaryCount >= planCount;
  const status = isComplete ? 'Complete' : summaryCount > 0 ? 'In Progress' : 'Planned';
  const today = todayISO();

  const rawContent = await safeReadFileAsync(rmPath);
  if (!rawContent) return cmdOk({ updated: false, reason: 'ROADMAP.md not found', plan_count: planCount, summary_count: summaryCount }, 'no roadmap');

  let roadmapContent = rawContent;
  const phaseEscaped = phaseNum.replace('.', '\\.');
  const dateField = isComplete ? ` ${today} ` : '  ';
  roadmapContent = roadmapContent.replace(new RegExp(`(\\|\\s*${phaseEscaped}\\.?\\s[^|]*\\|)[^|]*(\\|)\\s*[^|]*(\\|)\\s*[^|]*(\\|)`, 'i'), `$1 ${summaryCount}/${planCount} $2 ${status.padEnd(11)}$3${dateField}$4`);
  const planCountText = isComplete ? `${summaryCount}/${planCount} plans complete` : `${summaryCount}/${planCount} plans executed`;
  roadmapContent = roadmapContent.replace(new RegExp(`(#{2,4}\\s*Phase\\s+${phaseEscaped}[\\s\\S]*?\\*\\*Plans:\\*\\*\\s*)[^\\n]+`, 'i'), `$1${planCountText}`);
  if (isComplete) { roadmapContent = roadmapContent.replace(new RegExp(`(-\\s*\\[)[ ](\\]\\s*.*Phase\\s+${phaseEscaped}[:\\s][^\\n]*)`, 'i'), `$1x$2 (completed ${today})`); }
  await fsp.writeFile(rmPath, roadmapContent, 'utf-8');

  return cmdOk({ updated: true, phase: phaseNum, plan_count: planCount, summary_count: summaryCount, status, complete: isComplete }, `${summaryCount}/${planCount} ${status}`);
}
